sed -i '/<td className="p-4">{user.fullName}<\/td>/a \                              <td className="p-4 font-mono text-white/70" dir="ltr">{user.phone || "-"}</td>\n                              <td className="p-4">\n                                 <div className="flex items-center gap-2">\n                                    <span className="font-mono text-white/70">\n                                       {visiblePasswords.has(user.uid) ? (user.password || "---") : "••••••"}\n                                    </span>\n                                    {user.password && (\n                                       <button \n                                          onClick={() => {\n                                             const newVisible = new Set(visiblePasswords);\n                                             if (newVisible.has(user.uid)) newVisible.delete(user.uid);\n                                             else newVisible.add(user.uid);\n                                             setVisiblePasswords(newVisible);\n                                          }}\n                                          className="text-white/40 hover:text-white transition-colors"\n                                       >\n                                          {visiblePasswords.has(user.uid) ? <EyeOff size={14} /> : <Eye size={14} />}\n                                       </button>\n                                    )}\n                                 </div>\n                              </td>' src/components/admin/UserManager.tsx
